const EMO_LABEL={anxiety:"불안",sadness:"슬픔",anger:"분노",joy:"기쁨",doubt:"의문",decision:"고민",neutral:"이야기"};
const EMO_KW={anxiety:["불안","걱정","두렵","무서","초조","막막","긴장"],sadness:["슬프","우울","눈물","외로","공허","지치","힘들","지쳐","허무"],anger:["화","짜증","억울","분노","열받","미워","원망"],joy:["감사","기쁘","행복","설레","좋아","고마","뿌듯"],doubt:["의심","확신","정말","증거","왜","이해가","믿기"],decision:["결정","선택","고민","어떻게","방향","진로","갈림길"]};
const EMO_BIAS={anxiety:["john","andrew","james_alph"],sadness:["john","andrew","peter"],anger:["james","simon","matthew"],joy:["peter","thaddaeus"],doubt:["thomas","matthew","philip"],decision:["matthew","james","philip"],neutral:["john","peter","thaddaeus"]};
const MOCK_VERSES={anxiety:[{book:"빌립보서",chapter:4,verse:6,content:"아무 것도 염려하지 말고 다만 모든 일에 기도와 간구로 너희 구할 것을 감사함으로 하나님께 아뢰라"},{book:"이사야",chapter:41,verse:10,content:"두려워하지 말라 내가 너와 함께 함이라 놀라지 말라 나는 네 하나님이 됨이라"}],sadness:[{book:"시편",chapter:34,verse:18,content:"여호와는 마음이 상한 자를 가까이 하시고 충심으로 통회하는 자를 구원하시는도다"},{book:"마태복음",chapter:11,verse:28,content:"수고하고 무거운 짐 진 자들아 다 내게로 오라 내가 너희를 쉬게 하리라"}],doubt:[{book:"요한복음",chapter:20,verse:27,content:"믿음 없는 자가 되지 말고 믿는 자가 되라"}],neutral:[{book:"잠언",chapter:3,verse:5,content:"너는 마음을 다하여 여호와를 신뢰하고 네 명철을 의지하지 말라"}]};

/* ── 목업 API (백엔드 붙으면 이 함수들만 fetch로 교체) ─────────────────── */
const compat=(a,b)=>SCORES[a]?SCORES[a][TYPE_ORDER.indexOf(b)]:50;
const bestMbti=(m,n=3)=>SCORES[m]?TYPE_ORDER.map((t,i)=>[t,SCORES[m][i]]).filter(([t])=>t!==m).sort((x,y)=>y[1]-x[1]).slice(0,n).map(([t])=>t):[];
const inferEmotion=(t)=>{for(const[e,ws]of Object.entries(EMO_KW))if(ws.some(w=>t.includes(w)))return e;return"neutral";};
const versesFor=(e)=>(MOCK_VERSES[e]||MOCK_VERSES.neutral).map(v=>({...v,source:`${v.book} ${v.chapter}:${v.verse}`}));
function personaAnswer(p,el,msg){const L={peter:`그 마음 잘 안다네. 나도 파도 앞에서 흔들렸던 사람 아닌가. 그 ${el}, 여기 내려놓게.`,john:`그 ${el}을(를) 여기 다 내려놓아도 괜찮아요. 사랑은 언제나 우리를 먼저 품는답니다.`,thomas:`의심이 드는 게 당연해요. 함께 하나씩 짚어봅시다.`,james:`핵심부터 짚어보세. 그 ${el} 뒤에 진짜 원하는 게 무엇인가?`};return L[p.id]||`${p.name}(이)가 당신의 ${el}에 조용히 귀 기울입니다. 편히 이야기해 보세요.`;}

async function apiRecommend(message,userMbti,emoWeight=1){
  if(CONFIG.API_BASE){ /* 실서버 경로 */
    const r=await fetch(CONFIG.API_BASE+"/api/chat/recommend",{method:"POST",headers:{"Content-Type":"application/json","X-User-Mbti":userMbti},body:JSON.stringify({message,emo_weight:emoWeight})});
    return r.json();
  }
  const emo=inferEmotion(message),bias=EMO_BIAS[emo]||[];
  const ranked=Object.values(PEOPLE).filter(p=>p.id!=="jesus").map(p=>{const c=compat(userMbti,p.mbti)/25;const rank=bias.includes(p.id)?3-bias.indexOf(p.id):0;return{...p,best_mbti:bestMbti(p.mbti),compat:+c.toFixed(2),score:+(c+rank*0.6*emoWeight).toFixed(3)};}).sort((a,b)=>b.score-a.score);
  return {emotion:emo,emotion_label:EMO_LABEL[emo],ranked};
}
async function apiAnswer(personId,message,userMbti){
  if(CONFIG.API_BASE){
    const r=await fetch(CONFIG.API_BASE+"/api/chat/answer",{method:"POST",headers:{"Content-Type":"application/json","X-User-Mbti":userMbti},body:JSON.stringify({person_id:personId,message})});
    return r.json();
  }
  const emo=inferEmotion(message),p=PEOPLE[personId];
  return {person_id:personId,person_name:p.name,answer:personaAnswer(p,EMO_LABEL[emo],message),verses:versesFor(emo)};
}


/* ════════════════════════════════════════════════════════════════════════
   Eden 포털 v2 — Codapress 스타일 (에덴 정원 배경 + 큰 세리프 타이포)
   구조 변경 요약:
     · 접속 시 '홈'이 먼저 (로그인은 바로 뜨지 않음)
     · 헤더: 좌 로고 / 중앙 메뉴 / 우 로그인·회원가입 (로그인 시 회원정보)
     · 홈 중앙에 큰 채팅 바 + 콘텐츠 이동 칩
     · 비로그인 상태로 메시지 전송 → 로그인/회원가입 팝업 유도(상담은 회원 전용)
     · 로그인 페이지: 회원가입 버튼은 하단
   디자인 토큰(에덴 정원):
     bg 밝은 정원 · ink #22301C · muted #5E6B52 · accent(walnut/olive) #5B7B3A
     display: Cormorant(세리프) · body: Inter/Noto Serif KR
   ════════════════════════════════════════════════════════════════════════ */

const F = "Inter, 'Noto Serif KR', sans-serif";
const S = "Cormorant, 'Noto Serif KR', serif";
const INK = "#22301C", MUTED = "#5E6B52", ACCENT = "#5B7B3A", DEEP = "#3A4A28";
const CARD = "#FFFEFB", LINE = "#E4E5D6", CREAM = "#EEF0DF";
const BGURL = IMAGES.bg;

/* ── 폰트 로더 ─────────────────────────────────────────────────────────── */
function useFonts() {
  useEffect(() => {
    const id = "ed-fonts";
    if (!document.getElementById(id)) {
      const l = document.createElement("link");
      l.id = id; l.rel = "stylesheet";
      l.href = "https://fonts.googleapis.com/css2?family=Cormorant:ital,wght@0,500;0,600;0,700;1,500;1,600&family=Inter:wght@300;400;500;600;700&family=Noto+Serif+KR:wght@400;500;600;700&display=swap";
      document.head.appendChild(l);
    }
  }, []);
}

/* ── 공통 요소 ─────────────────────────────────────────────────────────── */
function Cross({ w = 15, color = ACCENT }) {
  return (
    <span style={{ display: "inline-block", width: w, height: w * 1.46, position: "relative" }}>
      <span style={{ position: "absolute", left: w * 0.4, width: w * 0.2, height: w * 1.46, background: color, borderRadius: 2 }} />
      <span style={{ position: "absolute", top: w * 0.33, width: w, height: w * 0.2, background: color, borderRadius: 2 }} />
    </span>
  );
}
function Wordmark({ size = 30, onClick }) {
  return (
    <div onClick={onClick} style={{ display: "flex", alignItems: "center", gap: 9, cursor: onClick ? "pointer" : "default" }}>
      <Cross w={size * 0.5} />
      <span style={{ fontFamily: S, fontSize: size, fontWeight: 700, letterSpacing: "-0.01em", color: INK }}>Eden</span>
    </div>
  );
}
function Avatar({ person, size = 64, glow }) {
  return (
    <img src={person.img} alt={person.name}
      style={{ width: size, height: size, borderRadius: "50%", objectFit: "cover", objectPosition: "center 22%",
        flexShrink: 0, display: "block", border: "1px solid rgba(255,255,255,0.8)",
        boxShadow: glow ? "0 0 0 5px rgba(91,123,58,0.12),0 10px 28px rgba(40,55,25,0.2)" : "0 2px 10px rgba(40,55,25,0.14)" }} />
  );
}
const inp = { width: "100%", boxSizing: "border-box", border: `1px solid ${LINE}`, borderRadius: 12,
  padding: "13px 15px", fontFamily: F, fontSize: 15, outline: "none", background: "#fff", color: INK };
const lb = { display: "block", fontFamily: F, fontSize: 11.5, fontWeight: 700, letterSpacing: "0.08em",
  color: ACCENT, margin: "18px 0 8px", textTransform: "uppercase" };

/* ══════════════ 헤더 ══════════════ */
const NAV = [["home", "홈"], ["chat", "말씀 상담"], ["diagnose", "제자 진단"], ["explore", "인물 탐색"], ["graph", "관계도"]];
function Header({ tab, setTab, user, onLogout, onAuth }) {
  return (
    <header style={{ position: "sticky", top: 0, zIndex: 20, display: "flex", alignItems: "center",
      padding: "14px 30px", background: "rgba(247,248,238,0.86)", backdropFilter: "blur(12px)",
      borderBottom: `1px solid ${LINE}` }}>
      <Wordmark size={27} onClick={() => setTab("home")} />
      <nav style={{ flex: 1, display: "flex", justifyContent: "center", gap: 30, overflowX: "auto" }}>
        {NAV.map(([k, t]) => (
          <button key={k} onClick={() => setTab(k)} style={{ position: "relative", background: "none", border: "none",
            cursor: "pointer", fontFamily: F, fontSize: 14, fontWeight: 500, whiteSpace: "nowrap",
            color: tab === k ? INK : MUTED, padding: "4px 0" }}>
            {t}
            {tab === k && <span style={{ position: "absolute", left: 0, right: 0, bottom: -3, height: 1.5, background: ACCENT }} />}
          </button>
        ))}
      </nav>
      <div style={{ display: "flex", alignItems: "center", gap: 12, flexShrink: 0 }}>
        {user ? (<>
          <span style={{ fontFamily: F, fontSize: 13, color: MUTED }}>{user.name} · <b style={{ color: ACCENT }}>{user.mbti}</b></span>
          <button onClick={onLogout} style={{ fontFamily: F, fontSize: 12.5, color: MUTED, background: "none",
            border: `1px solid ${LINE}`, borderRadius: 9, padding: "7px 12px", cursor: "pointer" }}>로그아웃</button>
        </>) : (<>
          <button onClick={() => onAuth("login")} style={{ fontFamily: F, fontSize: 13.5, fontWeight: 500,
            color: MUTED, background: "none", border: "none", cursor: "pointer", padding: "8px 4px" }}>로그인</button>
          <button onClick={() => onAuth("signup")} style={{ fontFamily: F, fontSize: 13.5, fontWeight: 600,
            color: "#F5F7EC", background: DEEP, border: "none", borderRadius: 100, padding: "10px 20px", cursor: "pointer" }}>회원가입</button>
        </>)}
      </div>
    </header>
  );
}

/* ══════════════ 홈 (히어로 + 큰 채팅바) ══════════════ */
const HOME_VERSES = [
  { t: "수고하고 무거운 짐 진 자들아 다 내게로 오라 내가 너희를 쉬게 하리라", r: "마태복음 11:28" },
  { t: "두려워하지 말라 내가 너와 함께 함이라", r: "이사야 41:10" },
  { t: "여호와는 나의 목자시니 내게 부족함이 없으리로다", r: "시편 23:1" },
];
const CHIPS = [
  { label: "불안할 때", seed: "요즘 마음이 많이 불안하고 초조해요" },
  { label: "감사하고 싶을 때", seed: "감사한 마음을 나누고 싶어요" },
  { label: "길을 정할 때", seed: "어떤 길로 가야 할지 고민이에요" },
  { label: "제자 진단", tab: "diagnose" },
];
function Home({ user, setTab, requireAuth, startConsult }) {
  const [verse] = useState(() => HOME_VERSES[Math.floor(Math.random() * HOME_VERSES.length)]);
  const [input, setInput] = useState("");

  function submit(seed) {
    const text = (seed ?? input).trim();
    if (!text) return;
    if (!user) { requireAuth("signup"); return; }   // 비로그인 → 회원가입 유도
    startConsult(text);                              // 로그인 상태 → 상담 시작
  }

  return (
    <section style={{ minHeight: "calc(100vh - 60px)", display: "flex", flexDirection: "column",
      alignItems: "center", justifyContent: "center", textAlign: "center", padding: "60px 24px 80px",
      position: "relative", background: `${CREAM} url("${BGURL}") center/cover no-repeat` }}>
      <div style={{ position: "absolute", inset: 0, background: "linear-gradient(180deg,rgba(238,240,223,0.32),rgba(238,240,223,0.8))" }} />
      <div style={{ position: "relative", width: "100%", maxWidth: 900 }}>
        <p style={{ fontFamily: F, fontSize: 12, letterSpacing: "0.26em", color: ACCENT, fontWeight: 600,
          textTransform: "uppercase", margin: "0 0 22px" }}>오늘의 말씀 · {verse.r}</p>
        <h1 style={{ fontFamily: S, fontWeight: 600, fontSize: "clamp(38px,7vw,74px)", lineHeight: 1.05,
          letterSpacing: "-0.02em", color: INK, margin: "0 0 18px", textShadow: "0 1px 16px rgba(255,252,240,0.7)" }}>
          마음의 짐을,<br /><span style={{ fontStyle: "italic", fontWeight: 500, color: ACCENT }}>말씀</span>으로 나누다
        </h1>
        <p style={{ fontFamily: F, fontSize: 16, lineHeight: 1.6, color: MUTED, maxWidth: 500,
          margin: "0 auto 40px" }}>
          {user ? `나의 ${user.name}아, 오늘의 마음을 적어보렴. ` : "오늘의 고민을 적어보세요. "}
          당신과 어울리는 제자가 성경으로 답합니다.
        </p>

        {/* 큰 채팅 바 (GPT/Claude식) */}
        <div style={{ width: "min(720px,92vw)", margin: "0 auto" }}>
          <div style={{ display: "flex", alignItems: "center", gap: 12, background: "rgba(255,255,252,0.9)",
            border: `1.5px solid rgba(255,255,255,0.9)`, borderRadius: 100, padding: "9px 9px 9px 24px",
            boxShadow: "0 20px 50px rgba(40,55,25,0.16)" }}>
            <input value={input} onChange={e => setInput(e.target.value)}
              onKeyDown={e => { if (e.key === "Enter") submit(); }}
              placeholder="요즘 마음이 어떤가요…"
              style={{ flex: 1, border: "none", outline: "none", background: "transparent",
                fontFamily: F, fontSize: 16.5, color: INK }} />
            <button onClick={() => submit()} aria-label="보내기"
              style={{ width: 48, height: 48, borderRadius: "50%", background: DEEP, color: "#F5F7EC",
                border: "none", fontSize: 19, cursor: "pointer", flexShrink: 0 }}>↑</button>
          </div>
          <div style={{ display: "flex", gap: 10, justifyContent: "center", marginTop: 20, flexWrap: "wrap" }}>
            {CHIPS.map(c => (
              <button key={c.label} onClick={() => c.tab ? setTab(c.tab) : submit(c.seed)}
                style={{ fontFamily: F, fontSize: 13, fontWeight: 500, color: MUTED,
                  background: "rgba(255,255,252,0.72)", border: `1px solid ${LINE}`, padding: "9px 16px",
                  borderRadius: 100, cursor: "pointer" }}>
                {c.label}<span style={{ color: ACCENT, marginLeft: 5 }}>→</span>
              </button>
            ))}
          </div>
        </div>
      </div>
      <div style={{ position: "absolute", bottom: 26, left: 30, fontFamily: F, fontSize: 11,
        letterSpacing: "0.18em", color: "rgba(90,110,60,0.6)", textTransform: "uppercase" }}>Eden · 말씀 상담</div>
      <div style={{ position: "absolute", bottom: 26, right: 30, fontFamily: F, fontSize: 11,
        letterSpacing: "0.18em", color: "rgba(90,110,60,0.6)", textTransform: "uppercase" }}>예수와 12제자 · MBTI</div>
    </section>
  );
}

/* ══════════════ 인증 모달 (로그인/회원가입) ══════════════ */
const QUIZ = [
  { q: "사람을 만나면서 기운을 회복하나요?", yes: "E", no: "I" },
  { q: "혼자 있을 때, 상상이나 가능성을 자주 떠올리나요?", yes: "N", no: "S" },
  { q: "결정할 때 감정보다 논리를 먼저 따지나요?", yes: "T", no: "F" },
  { q: "계획대로보다 즉흥적으로 움직이는 게 편한가요?", yes: "P", no: "J" },
];
function AuthModal({ initial = "login", onClose, onAuth }) {
  const [mode, setMode] = useState(initial);
  const [f, setF] = useState({ email: "", password: "", name: "", gender: null, answers: [null, null, null, null] });
  const [mbtiMode, setMbtiMode] = useState("quiz");
  const [direct, setDirect] = useState("");
  const [err, setErr] = useState("");

  const computed = () => mbtiMode === "direct" ? direct : QUIZ.map((q, i) => f.answers[i] ? q.yes : q.no).join("");
  const quizDone = f.answers.every(a => a !== null);
  const canSignup = f.email && f.password && f.name && f.gender && (mbtiMode === "direct" ? direct.length === 4 : quizDone);
  const canLogin = f.email && f.password;
  const blue = f.gender === "adam", pink = f.gender === "eve";
  const accent = blue ? "#3B6EA5" : pink ? "#C05E86" : ACCENT;
  const accentBg = blue ? "#EAF1F9" : pink ? "#FBECF3" : "#EEF3E3";

  function submit() {
    setErr("");
    if (mode === "signup") {
      if (!canSignup) return;
      onAuth({ email: f.email, name: f.name, gender: f.gender, mbti: computed() });
    } else {
      if (!canLogin) return;
      onAuth({ email: f.email, name: f.email.split("@")[0], gender: "adam", mbti: "INFP" });
    }
  }

  return (
    <div onClick={onClose} style={{ position: "fixed", inset: 0, zIndex: 50, display: "flex",
      alignItems: "center", justifyContent: "center", padding: 18, overflow: "auto",
      background: `${CREAM} url("${BGURL}") center/cover`, }}>
      <div style={{ position: "absolute", inset: 0, background: "rgba(34,42,26,0.4)", backdropFilter: "blur(3px)" }} />
      <div onClick={e => e.stopPropagation()} style={{ position: "relative", width: "min(94vw,430px)",
        background: CARD, borderRadius: 22, padding: "30px 26px", boxShadow: "0 30px 80px rgba(20,26,12,0.4)", margin: "auto" }}>
        <Wordmark size={26} />
        <p style={{ fontFamily: F, fontSize: 13, color: MUTED, margin: "8px 0 22px" }}>
          {mode === "signup" ? "에덴에 오신 걸 환영합니다. 당신을 알려주세요." : "다시 만나 반갑습니다."}
        </p>

        <input value={f.email} onChange={e => setF({ ...f, email: e.target.value })} placeholder="이메일" style={inp} />
        <div style={{ height: 10 }} />
        <input type="password" value={f.password} onChange={e => setF({ ...f, password: e.target.value })} placeholder="비밀번호" style={inp} />

        {mode === "signup" && <>
          <div style={{ height: 10 }} />
          <input value={f.name} onChange={e => setF({ ...f, name: e.target.value })} placeholder="이름" style={inp} />

          <label style={lb}>당신은</label>
          <div style={{ display: "flex", gap: 10 }}>
            {[{ k: "adam", t: "아담의 후손", m: "♂", c: "#3B6EA5", bg: "#EAF1F9" },
              { k: "eve", t: "하와의 후손", m: "♀", c: "#C05E86", bg: "#FBECF3" }].map(o => {
              const on = f.gender === o.k;
              return (
                <button key={o.k} onClick={() => setF({ ...f, gender: o.k })}
                  style={{ flex: 1, padding: "12px 0", borderRadius: 13, cursor: "pointer", display: "flex",
                    alignItems: "center", justifyContent: "center", gap: 6, fontFamily: F, fontSize: 14, fontWeight: 600,
                    border: on ? `2px solid ${o.c}` : `1px solid ${LINE}`, background: on ? o.bg : "#fff",
                    color: on ? o.c : MUTED }}>
                  {o.t}<span style={{ fontSize: 16, fontWeight: 700, color: on ? o.c : "#B4B0A8" }}>{o.m}</span>
                </button>
              );
            })}
          </div>

          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginTop: 18, marginBottom: 8 }}>
            <label style={{ ...lb, margin: 0 }}>MBTI</label>
            <div style={{ display: "flex", gap: 4 }}>
              {[["quiz", "4문항 검사"], ["direct", "직접 선택"]].map(([k, t]) => (
                <button key={k} onClick={() => setMbtiMode(k)} style={{ fontFamily: F, fontSize: 11, fontWeight: 600,
                  padding: "5px 10px", borderRadius: 20, cursor: "pointer", border: "none",
                  background: mbtiMode === k ? DEEP : "#EDF0E2", color: mbtiMode === k ? "#F5F7EC" : MUTED }}>{t}</button>
              ))}
            </div>
          </div>

          {mbtiMode === "quiz" ? (
            <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
              {QUIZ.map((q, i) => (
                <div key={i} style={{ border: `1px solid ${LINE}`, borderRadius: 12, padding: "10px 12px" }}>
                  <div style={{ fontFamily: F, fontSize: 13, color: INK, marginBottom: 8, lineHeight: 1.4 }}>{i + 1}. {q.q}</div>
                  <div style={{ display: "flex", gap: 6 }}>
                    {[[true, "그렇다"], [false, "아니다"]].map(([v, t]) => {
                      const on = f.answers[i] === v;
                      return (
                        <button key={String(v)} onClick={() => { const a = [...f.answers]; a[i] = v; setF({ ...f, answers: a }); }}
                          style={{ flex: 1, padding: "8px 0", borderRadius: 9, cursor: "pointer", fontFamily: F, fontSize: 12.5,
                            fontWeight: 600, border: on ? `1.5px solid ${accent}` : `1px solid ${LINE}`,
                            background: on ? accentBg : "#fff", color: on ? accent : MUTED }}>{t}</button>
                      );
                    })}
                  </div>
                </div>
              ))}
              {quizDone && <div style={{ fontFamily: F, fontSize: 12, color: ACCENT, textAlign: "right" }}>예상 유형: <b>{computed()}</b></div>}
            </div>
          ) : (
            <select value={direct} onChange={e => setDirect(e.target.value)} style={{ ...inp, cursor: "pointer" }}>
              <option value="">유형 선택</option>
              {TYPE_ORDER.map(t => <option key={t} value={t}>{t}</option>)}
            </select>
          )}
        </>}

        {err && <div style={{ fontFamily: F, fontSize: 12.5, color: "#C0392B", marginTop: 12 }}>{err}</div>}

        <button onClick={submit} disabled={mode === "signup" ? !canSignup : !canLogin}
          style={{ marginTop: 20, width: "100%", padding: "14px 0", borderRadius: 14, border: "none",
            fontFamily: F, fontSize: 15, fontWeight: 700, cursor: (mode === "signup" ? canSignup : canLogin) ? "pointer" : "not-allowed",
            background: (mode === "signup" ? canSignup : canLogin) ? DEEP : "#CBD0BE", color: "#F5F7EC" }}>
          {mode === "signup" ? "가입하고 에덴 들어가기" : "로그인"}
        </button>

        {/* 로그인 화면: 회원가입 버튼은 하단 */}
        <div style={{ textAlign: "center", marginTop: 16, fontFamily: F, fontSize: 13, color: MUTED }}>
          {mode === "signup" ? "이미 계정이 있나요? " : "아직 계정이 없나요? "}
          <span onClick={() => { setMode(mode === "signup" ? "login" : "signup"); setErr(""); }}
            style={{ color: ACCENT, fontWeight: 700, cursor: "pointer" }}>
            {mode === "signup" ? "로그인" : "회원가입"}
          </span>
        </div>
      </div>
    </div>
  );
}

/* ══════════════ 말씀 상담 (Hybrid RAG 챗봇) ══════════════ */
function TypingDots() {
  return (<span style={{ display: "inline-flex", gap: 5, padding: "4px 2px" }}>
    {[0, 1, 2].map(i => <span key={i} className="ed-dot" style={{ animationDelay: `${i * 0.2}s` }} />)}</span>);
}
function ChatConsult({ user, seed, clearSeed }) {
  const [msgs, setMsgs] = useState([]);
  const [input, setInput] = useState("");
  const [busy, setBusy] = useState(false);
  const [card, setCard] = useState(null);
  const [active, setActive] = useState(null);
  const [started, setStarted] = useState(false);
  const ref = useRef(null);
  const push = m => setMsgs(x => [...x, m]);

  useEffect(() => { ref.current?.scrollTo({ top: 9e9, behavior: "smooth" }); }, [msgs, busy, card]);
  // 홈에서 넘어온 seed 문장으로 자동 시작
  useEffect(() => { if (seed) { runFirst(seed); clearSeed?.(); } /* eslint-disable-next-line */ }, [seed]);

  async function runFirst(text) {
    setStarted(true); push({ role: "user", text }); setBusy(true);
    await new Promise(r => setTimeout(r, 480));
    const rec = await apiRecommend(text, user.mbti, 1); const top = rec.ranked[0];
    push({ role: "bot", personId: "jesus", text: `내 아이야, 그 ${rec.emotion_label}은(는) ${top.name}가 잘 들어줄 수 있겠구나. 먼저 어떤 벗인지 보여주마.` });
    setBusy(false); await new Promise(r => setTimeout(r, 400));
    setCard({ emotion: rec.emotion_label, lastText: text, order: rec.ranked, idx: 0, pass: 0, w: 1 });
  }
  async function send() {
    const text = input.trim(); if (!text || busy || card) return;
    setInput("");
    if (active) { setStarted(true); push({ role: "user", text }); setBusy(true); await new Promise(r => setTimeout(r, 480));
      const a = await apiAnswer(active.id, text, user.mbti); push({ role: "bot", personId: active.id, text: a.answer, verses: a.verses }); setBusy(false); return; }
    runFirst(text);
  }
  async function accept() {
    const p = card.order[card.idx], last = card.lastText; setCard(null); setActive(p); setBusy(true);
    push({ role: "bot", personId: "jesus", text: `그래, ${p.name}와 마음을 나눠보거라. 나는 늘 곁에 있으마.` });
    await new Promise(r => setTimeout(r, 560));
    const a = await apiAnswer(p.id, last, user.mbti); push({ role: "bot", personId: p.id, text: a.answer, verses: a.verses }); setBusy(false);
  }
  async function next() {
    let { pass, w, order, idx, lastText } = card; pass++; idx++;
    if (pass >= 2) { w = Math.min(3, w + 0.8); const r = await apiRecommend(lastText, user.mbti, w);
      const shown = new Set(order.slice(0, idx).map(p => p.id));
      order = [...r.ranked.filter(p => !shown.has(p.id)), ...order.slice(0, idx)]; idx = 0; }
    if (idx >= order.length) idx = order.length - 1;
    setCard({ ...card, order, idx, pass, w });
  }

  return (
    <div style={{ position: "relative", height: "calc(100vh - 60px)", display: "flex", flexDirection: "column",
      background: `${CREAM} url("${BGURL}") center/cover fixed` }}>
      <div style={{ position: "absolute", inset: 0, background: "rgba(247,248,238,0.82)" }} />
      {!started ? (
        <div style={{ position: "relative", flex: 1, display: "flex", flexDirection: "column",
          alignItems: "center", justifyContent: "center", padding: "0 20px" }}>
          <Avatar person={PEOPLE.jesus} size={98} glow />
          <p style={{ fontFamily: S, fontSize: 27, fontWeight: 600, margin: "20px 0 6px", textAlign: "center", color: INK }}>
            나의 {user.name}아, 편히 말해보거라.</p>
          <p style={{ fontFamily: F, fontSize: 13.5, color: MUTED, marginBottom: 28 }}>마음을 나누면, 어울리는 벗이 성경으로 답합니다.</p>
          <Composer value={input} onChange={setInput} onSend={send} big disabled={!!card} />
        </div>
      ) : (<>
        <div ref={ref} style={{ position: "relative", flex: 1, overflowY: "auto", padding: "22px 18px",
          maxWidth: 720, width: "100%", margin: "0 auto", boxSizing: "border-box" }}>
          {msgs.map((m, i) => <Bubble key={i} m={m} />)}
          {busy && <div style={{ display: "flex", gap: 10, alignItems: "flex-end" }}><div style={{ width: 34 }} />
            <div style={{ background: CARD, borderRadius: 18, padding: "6px 12px" }}><TypingDots /></div></div>}
        </div>
        <div style={{ position: "relative", padding: "12px 18px 18px", borderTop: `1px solid ${LINE}`,
          background: "rgba(255,255,252,0.9)", maxWidth: 720, width: "100%", margin: "0 auto", boxSizing: "border-box" }}>
          <Composer value={input} onChange={setInput} onSend={send} disabled={!!card}
            placeholder={card ? "추천된 벗을 먼저 확인해보세요…" : undefined} />
        </div>
      </>)}
      {card && <ProfileCard person={card.order[card.idx]} onAccept={accept} onNext={next} />}
    </div>
  );
}
function Bubble({ m }) {
  if (m.role === "user") return (
    <div style={{ display: "flex", justifyContent: "flex-end", marginBottom: 14 }}>
      <div style={{ maxWidth: "76%", padding: "11px 15px", borderRadius: 20, borderBottomRightRadius: 6,
        background: DEEP, color: "#F5F7EC", fontFamily: F, fontSize: 14.5, lineHeight: 1.55 }}>{m.text}</div></div>);
  const p = PEOPLE[m.personId];
  return (
    <div style={{ display: "flex", gap: 10, marginBottom: 14, alignItems: "flex-end" }}>
      <Avatar person={p} size={34} />
      <div style={{ maxWidth: "78%" }}>
        <div style={{ fontFamily: F, fontSize: 11.5, color: MUTED, margin: "0 0 3px 4px" }}>{p.name} · {p.mbti}</div>
        <div style={{ padding: "11px 15px", borderRadius: 20, borderBottomLeftRadius: 6, background: CARD,
          color: INK, fontFamily: F, fontSize: 14.5, lineHeight: 1.55, border: `1px solid ${LINE}` }}>{m.text}</div>
        {m.verses && m.verses.length > 0 && (
          <div style={{ marginTop: 6, marginLeft: 4, display: "flex", flexDirection: "column", gap: 4 }}>
            {m.verses.map((v, i) => (
              <div key={i} style={{ fontFamily: F, fontSize: 11.5, color: "#8A9578",
                borderLeft: `2px solid ${ACCENT}`, paddingLeft: 8, lineHeight: 1.4 }}>
                <b>{v.source}</b> {v.content}</div>))}
          </div>)}
      </div>
    </div>);
}
function Composer({ value, onChange, onSend, big, disabled, placeholder }) {
  return (
    <div style={{ display: "flex", gap: 10, alignItems: "flex-end", width: "100%",
      maxWidth: big ? 560 : "100%", opacity: disabled ? 0.55 : 1 }}>
      <textarea value={value} onChange={e => onChange(e.target.value)} disabled={disabled}
        onKeyDown={e => { if (e.key === "Enter" && !e.shiftKey) { e.preventDefault(); onSend(); } }}
        placeholder={placeholder || "마음에 있는 것을 적어보세요…"} rows={1}
        style={{ flex: 1, resize: "none", border: `1px solid ${LINE}`, borderRadius: 22, padding: "13px 18px",
          fontFamily: F, fontSize: 15, lineHeight: 1.4, outline: "none", background: "#fff", color: INK,
          maxHeight: 140, boxShadow: big ? "0 6px 22px rgba(40,55,25,0.1)" : "none" }} />
      <button onClick={onSend} disabled={disabled} style={{ border: "none", borderRadius: "50%", width: 46, height: 46,
        cursor: disabled ? "not-allowed" : "pointer", background: DEEP, color: "#F5F7EC", fontSize: 18, flexShrink: 0 }}>↑</button>
    </div>);
}
const cl = { fontFamily: F, fontSize: 11, fontWeight: 700, letterSpacing: "0.05em", color: ACCENT, textTransform: "uppercase" };
function CRow({ l, v }) {
  return (<div style={{ display: "flex", gap: 12, padding: "7px 0", borderBottom: `1px solid #EEF0E2` }}>
    <div style={{ ...cl, width: 96, flexShrink: 0 }}>{l}</div>
    <div style={{ fontFamily: F, fontSize: 14, color: INK, lineHeight: 1.45 }}>{v}</div></div>);
}
function ProfileCard({ person, onAccept, onNext }) {
  return (
    <div style={{ position: "fixed", inset: 0, zIndex: 40, display: "flex", alignItems: "center",
      justifyContent: "center", padding: 18, background: "rgba(34,42,26,0.4)", backdropFilter: "blur(4px)" }}>
      <div style={{ width: "min(95vw,440px)", background: CARD, borderRadius: 24, overflow: "hidden",
        boxShadow: "0 26px 70px rgba(20,26,12,0.4)" }}>
        <div style={{ display: "flex", gap: 16, padding: "22px 22px 18px", background: "linear-gradient(135deg,#EDF0E1,#FBFCF7)" }}>
          <Avatar person={person} size={90} />
          <div style={{ flex: 1, minWidth: 0 }}>
            <div style={{ display: "flex", alignItems: "baseline", gap: 8, flexWrap: "wrap" }}>
              <span style={{ fontFamily: S, fontSize: 24, fontWeight: 700, color: INK }}>{person.name}</span>
              <span style={{ fontFamily: F, fontSize: 12, fontWeight: 700, color: ACCENT, background: "#EAF0DE", padding: "2px 8px", borderRadius: 20 }}>{person.mbti}</span>
            </div>
            <div style={{ fontFamily: F, fontSize: 12.5, color: MUTED, marginTop: 5, lineHeight: 1.4 }}>{person.epithet}</div>
          </div>
        </div>
        <div style={{ padding: "18px 22px 8px" }}>
          <CRow l="성향" v={person.traits} />
          <CRow l="잘 맞는 MBTI" v={(person.best_mbti || bestMbti(person.mbti)).join(" · ")} />
          <CRow l="연관 성경서" v={(person.books || []).join(" · ") || "—"} />
          <div style={{ marginTop: 14 }}>
            <div style={cl}>명언</div>
            <blockquote style={{ margin: "6px 0 0", padding: "12px 16px", borderLeft: `3px solid ${ACCENT}`,
              background: "#F6F8EF", borderRadius: "0 10px 10px 0", fontFamily: S, fontSize: 16.5, lineHeight: 1.5, color: INK }}>
              “{person.quote}”<div style={{ fontFamily: F, fontSize: 11.5, color: "#8A9578", marginTop: 6 }}>— {person.quote_ref}</div>
            </blockquote>
          </div>
        </div>
        <div style={{ display: "flex", gap: 10, padding: "12px 22px 22px" }}>
          <button onClick={onNext} style={{ flex: 1, padding: "13px 0", borderRadius: 14, cursor: "pointer",
            border: `1px solid ${LINE}`, background: "#fff", color: MUTED, fontFamily: F, fontSize: 14, fontWeight: 600 }}>다른 벗 추천</button>
          <button onClick={onAccept} style={{ flex: 1.4, padding: "13px 0", borderRadius: 14, cursor: "pointer",
            border: "none", background: DEEP, color: "#F5F7EC", fontFamily: F, fontSize: 14, fontWeight: 700 }}>이 벗과 대화하기</button>
        </div>
      </div>
    </div>);
}

/* ══════════════ 제자 진단 ══════════════ */
function Diagnose({ user }) {
  const [mbti, setMbti] = useState(user?.mbti || "INFJ");
  const matches = Object.values(PEOPLE).filter(p => p.id !== "jesus")
    .map(p => ({ ...p, score: compat(mbti, p.mbti), best_mbti: bestMbti(p.mbti) }))
    .sort((a, b) => b.score - a.score).slice(0, 3);
  const top = matches[0];
  return (
    <div style={{ maxWidth: 720, margin: "0 auto", padding: "44px 22px 70px" }}>
      <p style={{ fontFamily: F, fontSize: 12, letterSpacing: "0.2em", color: ACCENT, fontWeight: 600, textTransform: "uppercase", margin: 0 }}>제자 진단</p>
      <h2 style={{ fontFamily: S, fontSize: 34, fontWeight: 600, color: INK, margin: "6px 0 4px" }}>나와 닮은 제자</h2>
      <p style={{ fontFamily: F, fontSize: 14, color: MUTED, margin: "0 0 22px" }}>MBTI로 12제자와의 궁합을 봅니다. 유형을 바꿔가며 탐색해보세요.</p>
      <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 26 }}>
        <span style={{ fontFamily: F, fontSize: 13, color: ACCENT, fontWeight: 600 }}>내 유형</span>
        <select value={mbti} onChange={e => setMbti(e.target.value)} style={{ fontFamily: F, fontSize: 14,
          padding: "8px 12px", borderRadius: 10, border: `1px solid ${LINE}`, cursor: "pointer", background: "#fff" }}>
          {TYPE_ORDER.map(t => <option key={t}>{t}</option>)}</select>
      </div>
      <div style={{ background: CARD, border: `1px solid ${LINE}`, borderRadius: 22, padding: "24px 22px",
        marginBottom: 20, display: "flex", gap: 18, alignItems: "center" }}>
        <Avatar person={top} size={96} glow />
        <div style={{ flex: 1 }}>
          <div style={{ fontFamily: F, fontSize: 12, color: "#8A9578", fontWeight: 700, letterSpacing: "0.1em" }}>가장 잘 맞는 제자</div>
          <div style={{ fontFamily: S, fontSize: 28, fontWeight: 700, color: INK, margin: "2px 0 4px" }}>{top.name} <span style={{ fontSize: 15, color: ACCENT }}>{top.mbti}</span></div>
          <div style={{ fontFamily: F, fontSize: 13, color: MUTED, marginBottom: 6 }}>{top.epithet}</div>
          <div style={{ display: "inline-block", fontFamily: F, fontSize: 12.5, fontWeight: 700, color: DEEP,
            background: "#EAF0DE", padding: "3px 10px", borderRadius: 20 }}>궁합 {top.score}점</div>
        </div>
      </div>
      <div style={{ fontFamily: F, fontSize: 12, color: MUTED, fontWeight: 700, letterSpacing: "0.08em", marginBottom: 10 }}>다음으로 잘 맞는</div>
      <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
        {matches.slice(1).map(p => (
          <div key={p.id} style={{ display: "flex", alignItems: "center", gap: 14, background: CARD,
            border: `1px solid ${LINE}`, borderRadius: 16, padding: "14px 16px" }}>
            <Avatar person={p} size={52} />
            <div style={{ flex: 1 }}>
              <div style={{ fontFamily: S, fontSize: 18, fontWeight: 700, color: INK }}>{p.name} <span style={{ fontSize: 13, color: ACCENT }}>{p.mbti}</span></div>
              <div style={{ fontFamily: F, fontSize: 12.5, color: MUTED }}>{p.traits}</div>
            </div>
            <div style={{ fontFamily: F, fontSize: 13, fontWeight: 700, color: ACCENT }}>{p.score}점</div>
          </div>))}
      </div>
    </div>);
}

/* ══════════════ 인물 탐색 ══════════════ */
function Explore() {
  const [sel, setSel] = useState(null);
  const list = Object.values(PEOPLE);
  return (
    <div style={{ maxWidth: 840, margin: "0 auto", padding: "44px 22px 70px" }}>
      <p style={{ fontFamily: F, fontSize: 12, letterSpacing: "0.2em", color: ACCENT, fontWeight: 600, textTransform: "uppercase", margin: 0 }}>인물 탐색</p>
      <h2 style={{ fontFamily: S, fontSize: 34, fontWeight: 600, color: INK, margin: "6px 0 4px" }}>예수와 12제자</h2>
      <p style={{ fontFamily: F, fontSize: 14, color: MUTED, margin: "0 0 24px" }}>인물을 눌러 성향·명언·연관 성경서를 살펴보세요.</p>
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill,minmax(96px,1fr))", gap: "24px 12px" }}>
        {list.map(p => (
          <button key={p.id} onClick={() => setSel(p)} style={{ display: "flex", flexDirection: "column",
            alignItems: "center", gap: 8, background: "none", border: "none", cursor: "pointer" }}>
            <Avatar person={p} size={72} glow={p.id === "jesus"} />
            <span style={{ fontFamily: F, fontSize: 12.5, fontWeight: 600, color: INK, textAlign: "center" }}>{p.name}</span>
            <span style={{ fontFamily: F, fontSize: 10.5, color: "#8A9578" }}>{p.mbti}</span>
          </button>))}
      </div>
      {sel && (
        <div onClick={() => setSel(null)} style={{ position: "fixed", inset: 0, zIndex: 40, display: "flex",
          alignItems: "center", justifyContent: "center", padding: 18, background: "rgba(34,42,26,0.4)", backdropFilter: "blur(4px)" }}>
          <div onClick={e => e.stopPropagation()} style={{ width: "min(95vw,440px)", background: CARD, borderRadius: 24,
            overflow: "hidden", boxShadow: "0 26px 70px rgba(20,26,12,0.4)" }}>
            <div style={{ display: "flex", gap: 16, padding: 22, background: "linear-gradient(135deg,#EDF0E1,#FBFCF7)" }}>
              <Avatar person={sel} size={90} glow={sel.id === "jesus"} />
              <div style={{ flex: 1, minWidth: 0 }}>
                <div style={{ display: "flex", alignItems: "baseline", gap: 8, flexWrap: "wrap" }}>
                  <span style={{ fontFamily: S, fontSize: 24, fontWeight: 700, color: INK }}>{sel.name}</span>
                  <span style={{ fontFamily: F, fontSize: 12, fontWeight: 700, color: ACCENT, background: "#EAF0DE", padding: "2px 8px", borderRadius: 20 }}>{sel.mbti}</span>
                </div>
                <div style={{ fontFamily: F, fontSize: 12.5, color: MUTED, marginTop: 5 }}>{sel.epithet}</div>
              </div>
            </div>
            <div style={{ padding: "18px 22px 22px" }}>
              <CRow l="성향" v={sel.traits} /><CRow l="잘 맞는 MBTI" v={bestMbti(sel.mbti).join(" · ")} /><CRow l="연관 성경서" v={(sel.books || []).join(" · ") || "—"} />
              <blockquote style={{ margin: "14px 0 0", padding: "12px 16px", borderLeft: `3px solid ${ACCENT}`,
                background: "#F6F8EF", borderRadius: "0 10px 10px 0", fontFamily: S, fontSize: 16, lineHeight: 1.5, color: INK }}>
                “{sel.quote}”<div style={{ fontFamily: F, fontSize: 11.5, color: "#8A9578", marginTop: 6 }}>— {sel.quote_ref}</div>
              </blockquote>
              <button onClick={() => setSel(null)} style={{ marginTop: 18, width: "100%", padding: "12px 0",
                borderRadius: 12, border: "none", background: DEEP, color: "#F5F7EC", fontFamily: F, fontSize: 14, fontWeight: 600, cursor: "pointer" }}>닫기</button>
            </div>
          </div>
        </div>)}
    </div>);
}

/* ══════════════ 관계도 ══════════════ */
function GraphView() {
  const people = Object.values(PEOPLE).filter(p => p.id !== "jesus");
  const cx = 380, cy = 300, R = 210;
  const typePos = {};
  TYPE_ORDER.forEach((t, i) => { const a = (i / TYPE_ORDER.length) * Math.PI * 2 - Math.PI / 2; typePos[t] = { x: cx + R * Math.cos(a), y: cy + R * Math.sin(a) }; });
  return (
    <div style={{ maxWidth: 840, margin: "0 auto", padding: "44px 22px 70px" }}>
      <p style={{ fontFamily: F, fontSize: 12, letterSpacing: "0.2em", color: ACCENT, fontWeight: 600, textTransform: "uppercase", margin: 0 }}>관계도</p>
      <h2 style={{ fontFamily: S, fontSize: 34, fontWeight: 600, color: INK, margin: "6px 0 4px" }}>MBTI · 제자 관계도</h2>
      <p style={{ fontFamily: F, fontSize: 14, color: MUTED, margin: "0 0 22px" }}>16가지 유형과 제자가 어떻게 이어지는지 보여줍니다. (Neo4j 그래프의 축소판)</p>
      <div style={{ background: CARD, border: `1px solid ${LINE}`, borderRadius: 20, overflow: "hidden" }}>
        <svg viewBox="0 0 760 600" style={{ width: "100%", display: "block" }}>
          {people.map(p => { const tp = typePos[p.mbti]; const a = Math.atan2(tp.y - cy, tp.x - cx);
            const px = cx + (R + 70) * Math.cos(a), py = cy + (R + 70) * Math.sin(a);
            return <line key={p.id} x1={tp.x} y1={tp.y} x2={px} y2={py} stroke="#D6DCC4" strokeWidth="1.5" />; })}
          {TYPE_ORDER.map(t => { const pos = typePos[t]; return (
            <g key={t}><circle cx={pos.x} cy={pos.y} r="20" fill="#EAF0DE" stroke={ACCENT} strokeWidth="1" />
              <text x={pos.x} y={pos.y + 3.5} textAnchor="middle" style={{ fontFamily: F, fontSize: 9, fontWeight: 700, fill: DEEP }}>{t}</text></g>); })}
          {people.map(p => { const tp = typePos[p.mbti]; const a = Math.atan2(tp.y - cy, tp.x - cx);
            const px = cx + (R + 70) * Math.cos(a), py = cy + (R + 70) * Math.sin(a);
            return <g key={p.id}><circle cx={px} cy={py} r="15" fill={DEEP} />
              <text x={px} y={py + 3} textAnchor="middle" style={{ fontFamily: F, fontSize: 8.5, fontWeight: 600, fill: "#F5F7EC" }}>{p.name.slice(0, 2)}</text></g>; })}
          <text x={cx} y={cy} textAnchor="middle" style={{ fontFamily: S, fontSize: 16, fontWeight: 700, fill: "#B7C29E" }}>Eden</text>
        </svg>
      </div>
      <p style={{ fontFamily: F, fontSize: 11.5, color: "#A6B090", marginTop: 10, textAlign: "center" }}>안쪽 원 = MBTI 16유형 · 바깥 = 해당 유형의 제자</p>
    </div>);
}

/* ══════════════ 루트 ══════════════ */
export default function App() {
  useFonts();
  const [user, setUser] = useState(null);
  const [tab, setTab] = useState("home");
  const [authMode, setAuthMode] = useState(null);   // null | "login" | "signup"
  const [seed, setSeed] = useState(null);           // 홈에서 넘긴 첫 상담 문장

  function handleAuth(u) { setUser(u); setAuthMode(null); }
  function startConsult(text) { setSeed(text); setTab("chat"); }

  return (
    <div style={{ background: "#F7F8EE", minHeight: "100vh" }}>
      <style>{`.ed-dot{width:7px;height:7px;border-radius:50%;background:#B7C29E;display:inline-block;animation:edBlink 1.1s infinite ease-in-out}@keyframes edBlink{0%,60%,100%{opacity:.3;transform:translateY(0)}30%{opacity:1;transform:translateY(-3px)}}@media(prefers-reduced-motion:reduce){*{animation:none!important;transition:none!important}} *::-webkit-scrollbar{width:9px;height:9px} *::-webkit-scrollbar-thumb{background:#D6DCC4;border-radius:9px}`}</style>
      <Header tab={tab} setTab={setTab} user={user} onLogout={() => { setUser(null); setTab("home"); }} onAuth={setAuthMode} />
      {tab === "home" && <Home user={user} setTab={setTab} requireAuth={setAuthMode} startConsult={startConsult} />}
      {tab === "chat" && (user
        ? <ChatConsult user={user} seed={seed} clearSeed={() => setSeed(null)} />
        : <GateForMembers onAuth={setAuthMode} />)}
      {tab === "diagnose" && <Diagnose user={user} />}
      {tab === "explore" && <Explore />}
      {tab === "graph" && <GraphView />}
      {authMode && <AuthModal initial={authMode} onClose={() => setAuthMode(null)} onAuth={handleAuth} />}
    </div>
  );
}
/* 상담 탭인데 비로그인일 때 */
function GateForMembers({ onAuth }) {
  return (
    <div style={{ minHeight: "calc(100vh - 60px)", display: "flex", flexDirection: "column",
      alignItems: "center", justifyContent: "center", textAlign: "center", padding: "0 24px",
      background: `${CREAM} url("${BGURL}") center/cover` }}>
      <div style={{ background: "rgba(255,255,252,0.9)", borderRadius: 22, padding: "36px 30px",
        boxShadow: "0 20px 50px rgba(40,55,25,0.16)", maxWidth: 400 }}>
        <Cross w={26} />
        <h3 style={{ fontFamily: S, fontSize: 26, fontWeight: 600, color: INK, margin: "14px 0 8px" }}>말씀 상담은 회원 전용이에요</h3>
        <p style={{ fontFamily: F, fontSize: 14, color: MUTED, margin: "0 0 22px", lineHeight: 1.6 }}>
          가입하면 당신의 MBTI에 맞는 제자가<br />성경으로 마음을 나눠드립니다.</p>
        <div style={{ display: "flex", gap: 10, justifyContent: "center" }}>
          <button onClick={() => onAuth("login")} style={{ padding: "12px 20px", borderRadius: 12,
            border: `1px solid ${LINE}`, background: "#fff", color: MUTED, fontFamily: F, fontSize: 14, fontWeight: 600, cursor: "pointer" }}>로그인</button>
          <button onClick={() => onAuth("signup")} style={{ padding: "12px 22px", borderRadius: 12, border: "none",
            background: DEEP, color: "#F5F7EC", fontFamily: F, fontSize: 14, fontWeight: 700, cursor: "pointer" }}>회원가입</button>
        </div>
      </div>
    </div>);
}
